 * 1. Reemplaza el prompt de Google por la nueva versión vibrante.
 * 2. Si un prompt es un batch JSON, extrae solo la variante principal (ej. Pizza Hut).
 */
const transformAndCleanup = (item: PromptItem): PromptItem => {
  const cleanTitle = item.title.toUpperCase();

  // 1. Caso Específico: Google Stock Price
  if (cleanTitle.includes("GOOGLE") && cleanTitle.includes("STOCK PRICE")) {
    return {
      ...item,
      title: "GOOGLE (GOOG) STOCK PRICE & TECH CITY 3D RENDER",
      promptText: "A vibrant, isometric 3D render depicts a charming miniature city centered around a Google building, surrounded by iconic Google product symbols like YouTube, Android, Maps, Gmail, Drive, and a self-driving car. Tiny diverse characters interact within this playful tech landscape, while an overlay shows Google's stock price range and an upward trend"
    };
  }

  // 2. Caso General: Simplificación de Batches JSON
  try {
    const parsed = JSON.parse(item.promptText);

    // Si es un batch de generación
    if (parsed.batch_generation_requests && Array.isArray(parsed.batch_generation_requests)) {
      const requests = parsed.batch_generation_requests;

      // Intentar encontrar Pizza Hut si es un batch de marcas/comida
      let selectedRequest = requests.find((r: any) => 
        (r.brand_theme && r.brand_theme.toLowerCase().includes('pizza')) ||
