import { PromptItem } from '../types';
import { README_URL, BLACKLIST_KEYWORDS, RAW_IMAGE_PREFIX } from '../constants';

/**
 * Limpia y transforma prompts para asegurar que NO existan variantes.
 * Convierte batches complejos en activos individuales únicos.
 */
const transformAndCleanup = (item: PromptItem): PromptItem => {
  let { title, promptText } = item;
  const cleanTitle = title.toUpperCase();

  // 1. Regla de Oro: Google Stock Price (Asset Específico)
  if (cleanTitle.includes("GOOGLE") && (cleanTitle.includes("STOCK") || cleanTitle.includes("PRICE"))) {
    return {
      ...item,
      title: "GOOGLE (GOOG) TECH CITY 3D RENDER",
      promptText: "A vibrant, isometric 3D render depicts a charming miniature city centered around a Google building, surrounded by iconic Google product symbols like YouTube, Android, Maps, Gmail, Drive, and a self-driving car. Tiny diverse characters interact within this playful tech landscape, while an overlay shows Google's stock price range and an upward trend"
    };
  }

  // 2. Limpieza de Batches JSON
  try {
    const parsed = JSON.parse(promptText);

    // Si detectamos un batch de generación (común en el dataset)
    if (parsed.batch_generation_requests && Array.isArray(parsed.batch_generation_requests)) {
      const requests = parsed.batch_generation_requests;

      // Prioridad: Pizza Hut (según instrucciones de diseño)
      let selected = requests.find((r: any) => 
        JSON.stringify(r).toLowerCase().includes('pizza') || 
        JSON.stringify(r).toLowerCase().includes('hut')
      );

      // Si no hay pizza, tomamos el primero para evitar variantes
      if (!selected) selected = requests[0];

      return {
        ...item,
        promptText: JSON.stringify(selected, null, 2)
      };
    }

    // Si el JSON es un objeto simple pero tiene una propiedad 'prompts' (array)
    if (parsed.prompts && Array.isArray(parsed.prompts)) {
      return { ...item, promptText: parsed.prompts[0] };
    }
  } catch (e) {
    // No es JSON, procedemos a limpiar texto plano
  }

  // 3. Limpieza de Variantes en Texto Plano
  // Detecta patrones como "Variant 1:", "1.", "Option A:" y corta el resto
  const variantMarkers = [
    /\n\s*Variant\s*1[:.]/i,
    /\n\s*Option\s*A[:.]/i,
    /\n\s*1\s*[:.]\s/i,
    /\n\s*\[1\]\s/i
  ];

  for (const marker of variantMarkers) {
    if (marker.test(promptText)) {
      // Si el texto empieza con un marcador de variante, lo limpiamos pero nos quedamos solo con ese bloque
      const parts = promptText.split(/\n\s*(?:Variant|Option|Batch|\[?\d\]?)\s*[2-9B-Z][:.]/i);
      promptText = parts[0].replace(marker, '').trim();
      break;
    }
  }

  // Eliminar prefijos redundantes si quedaron tras el split
  promptText = promptText.replace(/^(?:Variant|Option|Prompt)\s*1\s*[:.]\s*/i, '').trim();

  return { ...item, promptText };
};

